import{_ as a,c as l,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"voicebox","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/voicebox-AI工具.md","filePath":"github汇总/AI工具/voicebox-AI工具.md"}'),o={name:"github汇总/AI工具/voicebox-AI工具.md"};function t(h,i,n,c,s,b){return e(),l("div",null,i[0]||(i[0]=[r('<h1 id="voicebox" tabindex="-1">voicebox <a class="header-anchor" href="#voicebox" aria-label="Permalink to “voicebox”">​</a></h1><h2 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h2><p>voicebox</p><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>jamiepine</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>AI工具</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>想要使用AI语音但担心隐私泄露，不想付费订阅云服务。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><p>开源本地语音克隆工作室，完全本地运行保护隐私。支持四种TTS引擎（Qwen3-TTS、LuxTTS、Chatterbox多语言版、Chatterbox快速版），覆盖23种语言。支持用几秒钟音频克隆声音。提供8种后期处理效果（变调、混响、延迟、合唱/镶边、压缩、增益、高通滤波、低通滤波）。故事编辑器支持多声音时间轴编辑，创建对话、播客和叙事内容。支持无限长度生成（自动分块和交叉淡入淡出）。提供REST API用于集成到其他项目。</p><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>完全本地运行，保护隐私</li><li>支持4种TTS引擎，23种语言</li><li>8种后期处理效果</li><li>故事编辑器支持多声音时间轴</li><li>无限长度生成</li><li>提供REST API</li><li>支持macOS、Windows、Linux</li><li>原生性能（Tauri + Rust）</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/jamiepine/voicebox" target="_blank" rel="noreferrer">https://github.com/jamiepine/voicebox</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>本教程适用于想要使用Voicebox进行语音克隆和生成的用户。</p><h3 id="主路径-下载桌面应用-推荐" tabindex="-1">主路径：下载桌面应用（推荐） <a class="header-anchor" href="#主路径-下载桌面应用-推荐" aria-label="Permalink to “主路径：下载桌面应用（推荐）”">​</a></h3><p><strong>步骤1：访问下载页面</strong></p><ul><li>目标：获取应用下载链接</li><li>位置：浏览器</li><li>操作：访问 <a href="https://voicebox.sh" target="_blank" rel="noreferrer">https://voicebox.sh</a> 或 GitHub Releases</li><li>成功标志：找到下载链接</li><li>失败处理：检查网络连接 <a href="/网络环境.html">海外网络环境配置 →</a></li></ul><p><strong>步骤2：下载对应平台版本</strong></p><ul><li>目标：下载安装包</li><li>位置：浏览器</li><li>操作：选择对应平台下载（macOS DMG、Windows MSI）</li><li>成功标志：安装包下载完成</li><li>失败处理：检查磁盘空间</li></ul><p><strong>步骤3：安装应用</strong></p><ul><li>目标：安装Voicebox</li><li>位置：本地</li><li>操作：运行安装包，按提示完成安装</li><li>成功标志：应用安装成功</li><li>失败处理：检查系统权限</li></ul><p><strong>步骤4：启动应用</strong></p><ul><li>目标：运行Voicebox</li><li>位置：桌面或应用菜单</li><li>操作：打开Voicebox应用</li><li>成功标志：应用窗口打开</li><li>失败处理：检查系统兼容性</li></ul><h3 id="备选路径-docker部署" tabindex="-1">备选路径：Docker部署 <a class="header-anchor" href="#备选路径-docker部署" aria-label="Permalink to “备选路径：Docker部署”">​</a></h3><p><strong>步骤1：克隆项目</strong></p><ul><li>目标：获取项目源码</li><li>位置：终端</li><li>命令：<code>git clone https://github.com/jamiepine/voicebox.git</code></li><li>成功标志：项目克隆成功</li><li>失败处理：检查网络连接</li></ul><p><strong>步骤2：启动Docker服务</strong></p><ul><li>目标：使用Docker Compose启动</li><li>位置：项目目录</li><li>命令：<code>docker compose up</code></li><li>成功标志：服务启动成功</li><li>失败处理：检查Docker是否运行</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ul><li>应用正常启动</li><li>可以创建新的语音配置文件</li><li>可以输入文本并生成语音</li></ul><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li><p><strong>macOS提示&quot;无法验证开发者&quot;</strong></p><ul><li>可能原因：应用未签名</li><li>解决步骤：系统设置 → 隐私与安全 → 仍要打开</li></ul></li><li><p><strong>GPU加速不工作</strong></p><ul><li>可能原因：缺少GPU驱动或CUDA</li><li>解决步骤：安装对应平台的GPU驱动</li></ul></li><li><p><strong>模型下载失败</strong></p><ul><li>可能原因：网络问题</li><li>解决步骤：配置代理或手动下载模型</li></ul></li></ol><h3 id="官方文档" tabindex="-1">官方文档 <a class="header-anchor" href="#官方文档" aria-label="Permalink to “官方文档”">​</a></h3><ul><li><a href="https://voicebox.sh" target="_blank" rel="noreferrer">Voicebox Documentation</a> <a href="/网络环境.html">海外网络环境配置 →</a></li><li><a href="https://github.com/jamiepine/voicebox/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">Contributing Guide</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ul>',40)]))}const u=a(o,[["render",t]]);export{p as __pageData,u as default};
